"""
    update_case(case_id)
    update_case(case_id, params::Dict{String,<:Any})

Updates an existing case.

# Arguments

- `case_id`: Required element for UpdateCase to identify the case ID for updates.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"actualIncidentStartDate"`: Optional element for UpdateCase to provide content for the
  incident start date field.

- `"caseMetadata"`: Update the case request with case metadata

- `"description"`: Optional element for UpdateCase to provide content for the description
  field.

- `"engagementType"`: Optional element for UpdateCase to provide content for the engagement
  type field. `Available engagement types include Security Incident | Investigation`.

- `"impactedAccountsToAdd"`: Optional element for UpdateCase to provide content to add
  accounts impacted.

  !!! note
      AWS account ID's may appear less than 12 characters and need to be zero-prepended. An
      example would be `123123123` which is nine digits, and with zero-prepend would be
      `000123123123`. Not zero-prepending to 12 digits could result in errors.

- `"impactedAccountsToDelete"`: Optional element for UpdateCase to provide content to add
  accounts impacted.

  !!! note
      AWS account ID's may appear less than 12 characters and need to be zero-prepended. An
      example would be `123123123` which is nine digits, and with zero-prepend would be
      `000123123123`. Not zero-prepending to 12 digits could result in errors.

- `"impactedAwsRegionsToAdd"`: Optional element for UpdateCase to provide content to add
  regions impacted.

- `"impactedAwsRegionsToDelete"`: Optional element for UpdateCase to provide content to
  remove regions impacted.

- `"impactedServicesToAdd"`: Optional element for UpdateCase to provide content to add
  services impacted.

- `"impactedServicesToDelete"`: Optional element for UpdateCase to provide content to remove
  services impacted.

- `"reportedIncidentStartDate"`: Optional element for UpdateCase to provide content for the
  customer reported incident start date field.

- `"threatActorIpAddressesToAdd"`: Optional element for UpdateCase to provide content to add
  additional suspicious IP addresses related to a case.

- `"threatActorIpAddressesToDelete"`: Optional element for UpdateCase to provide content to
  remove suspicious IP addresses from a case.

- `"title"`: Optional element for UpdateCase to provide content for the title field.

- `"watchersToAdd"`: Optional element for UpdateCase to provide content to add additional
  watchers to a case.

- `"watchersToDelete"`: Optional element for UpdateCase to provide content to remove
  existing watchers from a case.
"""
function update_case end

function update_case(caseId; aws_config::AbstractAWSConfig=current_aws_config())
    return security_ir(
        "POST",
        "/v1/cases/$(caseId)/update-case";
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_case(
    caseId, params::AbstractDict{String}; aws_config::AbstractAWSConfig=current_aws_config()
)
    return security_ir(
        "POST",
        "/v1/cases/$(caseId)/update-case",
        params;
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

